import { useState } from "react";
import { loginUser, res } from "../api/api";

export default function Login({ setIsLoggedIn }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

const handleLogin = async () => {
  // 1. Prepare data as URL-encoded form data
  const formData = new URLSearchParams();
  formData.append("username", email); // OAuth2 spec requires the key 'username'
  formData.append("password", password);

  // 2. Pass this formatted data to your login function
  const res = await loginUser(formData);

  
    if (res && res.access_token) {
      localStorage.setItem("token", res.access_token);
      setIsLoggedIn(true);
    } else if (res && res.error) {
      alert(res.error); // This will show "Invalid credentials"
    } else {
      alert("Something went wrong");
    }
};


  return (
    <div style={{ textAlign: "center", marginTop: "100px" }}>
      <h2>Login</h2>

      <input
        placeholder="Email"
        onChange={(e) => setEmail(e.target.value)}
      /><br /><br />

      <input
        placeholder="Password"
        type="password"
        onChange={(e) => setPassword(e.target.value)}
      /><br /><br />

      <button onClick={handleLogin}>Login</button>
    </div>
  );
}
